import{_ as a,o as r,c as i,ae as l}from"./chunks/framework.DhtYoOpx.js";const d=JSON.parse('{"title":"Vue 3.0 框架集合","description":"","frontmatter":{},"headers":[],"relativePath":"articles/vue/vue3-ui-frameworks.md","filePath":"articles/vue/vue3-ui-frameworks.md","lastUpdated":1776146674000}'),t={name:"articles/vue/vue3-ui-frameworks.md"};function n(o,e,u,s,p,h){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="vue-3-0-框架集合" tabindex="-1">Vue 3.0 框架集合 <a class="header-anchor" href="#vue-3-0-框架集合" aria-label="Permalink to &quot;Vue 3.0 框架集合&quot;">​</a></h1><p>Vue3 已经发布一段时间了，版本趋于稳定并且可以用于生产。本文推荐几个比较流行的 Vue 3 UI 框架。</p><h2 id="ant-design-vue" tabindex="-1">Ant Design Vue <a class="header-anchor" href="#ant-design-vue" aria-label="Permalink to &quot;Ant Design Vue&quot;">​</a></h2><p><a href="https://2x.antdv.com/components/overview/" target="_blank" rel="noreferrer">官方网站</a></p><p>Ant Design Vue 是一个非常成熟的框架，组件适应各种图标样式、字体和黑色主题。不断改进其 60 多个组件，基本覆盖项目大部分需求。</p><p><strong>特点</strong>：</p><ul><li>支持 SSR 和组合 API</li><li>包含复杂组件如数据表、确认框、模态框</li><li>GitHub 15k+ 颗星</li></ul><h2 id="balmui" tabindex="-1">BalmUI <a class="header-anchor" href="#balmui" aria-label="Permalink to &quot;BalmUI&quot;">​</a></h2><p><a href="https://next-material.balmjs.com/" target="_blank" rel="noreferrer">官方网站</a></p><p>BalmUI 基于谷歌的 Material Design，提供 Vue 插件和指令，以及高度可定制的组件。</p><p><strong>特点</strong>：</p><ul><li>支持复杂的内置指令</li><li>包含 debouncing 和 UI 波纹等效果</li></ul><h2 id="wave-ui" tabindex="-1">Wave UI <a class="header-anchor" href="#wave-ui" aria-label="Permalink to &quot;Wave UI&quot;">​</a></h2><p><a href="https://antoniandre.github.io/wave-ui/" target="_blank" rel="noreferrer">官方网站</a></p><p>Wave UI 是首批 Vue 3 UI 框架之一，提供 40+ 漂亮且响应迅速的组件。</p><p><strong>特点</strong>：</p><ul><li>组件非常漂亮，动画效果出色</li><li>企业级响应式 Vue 3 应用不错的选择</li></ul><h2 id="vuestic" tabindex="-1">Vuestic <a class="header-anchor" href="#vuestic" aria-label="Permalink to &quot;Vuestic&quot;">​</a></h2><p><a href="https://vuestic.dev/" target="_blank" rel="noreferrer">官方网站</a></p><p>Vuestic 是 Vue 最漂亮的开源管理面板之一，提供 50+ 组件。</p><p><strong>特点</strong>：</p><ul><li>优秀键盘导航支持</li><li>响应式设计，几乎适用于所有屏幕分辨率</li><li>无缝翻译支持</li></ul><h2 id="element-plus" tabindex="-1">Element Plus <a class="header-anchor" href="#element-plus" aria-label="Permalink to &quot;Element Plus&quot;">​</a></h2><p><a href="https://element-plus.org/" target="_blank" rel="noreferrer">官方网站</a></p><p>Element Plus 为 Vue 3 带来了大量组件，提供成熟的日期选择器、树、时间线等。</p><p><strong>特点</strong>：</p><ul><li>GitHub 11.1k+ 颗星</li><li>高定制性，通过 SCSS 变量</li><li>成熟的国际化系统</li></ul><h2 id="ionic" tabindex="-1">Ionic <a class="header-anchor" href="#ionic" aria-label="Permalink to &quot;Ionic&quot;">​</a></h2><p><a href="https://ionicframework.com/docs/vue/overview" target="_blank" rel="noreferrer">官方网站</a></p><p>Ionic 是最早提供 Vue 3 支持的 UI 框架之一，更倾向于移动 UI。</p><p><strong>特点</strong>：</p><ul><li>GitHub 45k+ 颗星</li><li>大公司使用（空客、艺电）</li><li>成熟的社区支持</li></ul><h2 id="naive-ui" tabindex="-1">Naive UI <a class="header-anchor" href="#naive-ui" aria-label="Permalink to &quot;Naive UI&quot;">​</a></h2><p><a href="https://www.naiveui.com/" target="_blank" rel="noreferrer">官方网站</a></p><p>Naive UI 由 Vue 创建者转发推荐，三个月内 GitHub 5.1k 颗星。</p><p><strong>特点</strong>：</p><ul><li>70+ 制作精良的组件</li><li>性能优异，可定制性极强</li><li>支持 TypeScript</li></ul><h2 id="quasar" tabindex="-1">Quasar <a class="header-anchor" href="#quasar" aria-label="Permalink to &quot;Quasar&quot;">​</a></h2><p><a href="https://next.quasar.dev/" target="_blank" rel="noreferrer">官方网站</a></p><p>Quasar 是一个完整的、以性能为中心的框架，可帮助构建 Vue 用户界面（SPA、PWA、SSR、移动和桌面）。</p><p><strong>特点</strong>：</p><ul><li>包含 Cordova、Capacitor 和 Electron</li><li>基于 Material Design</li><li>快速发布 Vue 3 支持</li></ul><h2 id="primevue" tabindex="-1">PrimeVUE <a class="header-anchor" href="#primevue" aria-label="Permalink to &quot;PrimeVUE&quot;">​</a></h2><p><a href="https://primefaces.org/primevue/" target="_blank" rel="noreferrer">官方网站</a></p><p>PrimeVUE 拥有 80+ 组件，是组件范围最广的框架之一。</p><p><strong>特点</strong>：</p><ul><li>包含仪表、滑块、树、图形等</li><li>集成 Vuelidate 表单验证</li><li>提供可视化编辑器</li></ul><hr><p>随着生态系统的迁移，从 Vue 2 迁移到 Vue 3 将变得更加容易。</p>',49)])])}const m=a(t,[["render",n]]);export{d as __pageData,m as default};
